mapper.select:
select r.id, r.name, r.phone, r.room_type as roomType, r.room_number as roomNumber, r.checkin, r.checkout, r.nights, r.amount, r.status, case r.status when 'pending' then '待确认' when 'confirmed' then '待入住' when 'checked_in' then '已入住' when 'checked_out' then '已退房' when 'cancelled' then '已取消' else '未知' end as statusName, ( select cir.checkin_time from check_in_record cir where cir.reservation_id = r.id order by cir.checkin_time desc limit 1 ) as checkInTime, r.remark from reservation r
and r.status = #{status}
order by r.id
